CustomField.formula:
IF(
    AND(
        ISBLANK(LastActivityDate),
        ISBLANK(LastModifiedDate)
    ),
    NULL,
    (
        /* Total days between today and last touch date */
        (
            TODAY() -
            IF(
                ISBLANK(LastActivityDate),
                /* Only LastModifiedDate present */
                DATEVALUE(LastModifiedDate),
                IF(
                    ISBLANK(LastModifiedDate),
                    /* Only LastActivityDate present */
                    LastActivityDate,
                    /* Both present: use numeric MAX of the two dates */
                    DATE(1900, 1, 1) +
                    MAX(
                        LastActivityDate - DATE(1900, 1, 1),
                        DATEVALUE(LastModifiedDate) - DATE(1900, 1, 1)
                    )
                )
            )
        )
        -
        /* Remove weekend days */
        (
            FLOOR(
                (
                    TODAY() -
                    IF(
                        ISBLANK(LastActivityDate),
                        DATEVALUE(LastModifiedDate),
                        IF(
                            ISBLANK(LastModifiedDate),
                            LastActivityDate,
                            DATE(1900, 1, 1) +
                            MAX(
                                LastActivityDate - DATE(1900, 1, 1),
                                DATEVALUE(LastModifiedDate) - DATE(1900, 1, 1)
                            )
                        )
                    )
                    +
                    WEEKDAY(
                        IF(
                            ISBLANK(LastActivityDate),
                            DATEVALUE(LastModifiedDate),
                            IF(
                                ISBLANK(LastModifiedDate),
                                LastActivityDate,
                                DATE(1900, 1, 1) +
                                MAX(
                                    LastActivityDate - DATE(1900, 1, 1),
                                    DATEVALUE(LastModifiedDate) - DATE(1900, 1, 1)
                                )
                            )
                        )
                    )
                    - 1
                ) / 7
            ) * 2
        )
        -
        IF(
            WEEKDAY(TODAY()) <
            WEEKDAY(
                IF(
                    ISBLANK(LastActivityDate),
                    DATEVALUE(LastModifiedDate),
                    IF(
                        ISBLANK(LastModifiedDate),
                        LastActivityDate,
                        DATE(1900, 1, 1) +
                        MAX(
                            LastActivityDate - DATE(1900, 1, 1),
                            DATEVALUE(LastModifiedDate) - DATE(1900, 1, 1)
                        )
                    )
                )
            ),
            2,
            0
        )
    )
)
